#include <stdio.h>
#include <stdlib.h>

// Structure for min-heap node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to insert a node into the min-heap
void insertNode(Node** root, int val) {
    Node* newNode = createNode(val);
    if (*root == NULL) {
        *root = newNode;
    } else {
        Node* current = *root;
        while (1) {
            if (val < current->val) {
                if (current->left == NULL) {
                    current->left = newNode;
                    break;
                }
                current = current->left;
            } else {
                if (current->right == NULL) {
                    current->right = newNode;
                    break;
                }
                current = current->right;
            }
        }
    }
}

// Function to delete the smallest node from the min-heap
int deleteNode(Node** root) {
    if (*root == NULL) return -1;
    Node* current = *root;
    while (current->left != NULL) {
        current = current->left;
    }
    int val = current->val;
    Node* parent = *root;
    while (parent->left != current) {
        parent = parent->left;
    }
    parent->left = NULL;
    free(current);
    return val;
}

// Function to find the kth largest element
int findKthLargest(Node* root, int k) {
    int count = 0;
    Node* current = root;
    while (current != NULL) {
        if (current->right != NULL) {
            count++;
            current = current->right;
        } else {
            break;
        }
    }
    if (count < k - 1) return -1;
    current = root;
    while (k > 1) {
        if (current->right != NULL) {
            current = current->right;
            k--;
        } else {
            break;
        }
    }
    return current->val;
}

int main() {
    int k, n;
    scanf("%d %d", &k, &n);
    Node* root = NULL;
    for (int i = 0; i < n; i++) {
        int val;
        scanf("%d", &val);
        insertNode(&root, val);
    }
    while (1) {
        int val;
        scanf("%d", &val);
        insertNode(&root, val);
        if (root->left != NULL) deleteNode(&root);
        printf("%d\n", findKthLargest(root, k));
    }
    return 0;
}

